    def minimumOperationsToMakeEqual(self, x: int, y: int) -> int:
        # If x is less than y, we can only reach y by incrementing x.
        # Dividing or decrementing would move x further away from y.
        if x < y:
            return y - x

        # If x is greater than or equal to y, we use BFS to find the minimum operations.
        # We need to explore states reachable from x.
        # The state space is bounded. Since x, y <= 10^4, and we only increment 
        # to reach multiples of 5 or 11, the maximum value we might reasonably 
        # visit is bounded. A safe upper bound is max(x, y) + 11 or slightly more.
        # Given constraints, 20000 is a safe upper limit.

        limit = 20000
        queue = [(x, 0)]  # (current_value, operations_count)
        visited = {x}

        while queue:
            curr, ops = queue.pop(0)

            if curr == y:
                return ops

            # Generate next states
            next_states = []

            # Operation 1: Decrement
            if curr - 1 >= 0:
                next_states.append(curr - 1)

            # Operation 2: Increment
            if curr + 1 <= limit:
                next_states.append(curr + 1)

            # Operation 3: Divide by 11
            if curr % 11 == 0:
                next_states.append(curr // 11)

            # Operation 4: Divide by 5
            if curr % 5 == 0:
                next_states.append(curr // 5)

            for nxt in next_states:
                if nxt not in visited:
                    visited.add(nxt)
                    queue.append((nxt, ops + 1))

        return -1  # Should not be reached given problem constraints
