    def lastNonEmptyString(self, s: str) -> str:
        # Count frequency of each character
        freq = {}
        for char in s:
            freq[char] = freq.get(char, 0) + 1

        # Find the maximum frequency K
        max_freq = max(freq.values())

        # We need to find the characters that remain after K-1 operations.
        # These are the characters that have frequency equal to K.
        # Specifically, for each such character, its K-th occurrence (which is the last one) remains.

        # We can find the last occurrence of each character that has frequency == max_freq.
        # To do this efficiently, we can iterate from right to left and record the first time we see a character
        # that has the max frequency. Or simply iterate left to right and update the last index.

        last_occurrence = {}
        for i, char in enumerate(s):
            if freq[char] == max_freq:
                last_occurrence[char] = i

        # Collect the characters at their last occurrence indices
        # We need to return them in the order they appear in the original string
        result_indices = sorted(last_occurrence.values())
        result_chars = [s[i] for i in result_indices]

        return "".join(result_chars)
