class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Optimize by building the prefix set from the smaller array to save space and time
        if len(arr1) > len(arr2):
            arr1, arr2 = arr2, arr1

        prefix_set = set()
        for num in arr1:
            s = str(num)
            # Add all prefixes of the current number to the set
            for i in range(1, len(s) + 1):
                prefix_set.add(s[:i])

        max_len = 0
        for num in arr2:
            s = str(num)
            # Check prefixes from longest to shortest, stopping early if we can't beat max_len
            for i in range(len(s), max_len, -1):
                if s[:i] in prefix_set:
                    max_len = i
                    break
        return max_len
